solution:
function reverseDigits(n) {
  let r = 0;
  while (n > 0) {
    r = r * 10 + (n % 10);
    n = Math.trunc(n / 10);
  }
  return r;
}

tests:
if (reverseDigits(1234) !== 4321) throw new Error('1234');
if (reverseDigits(120) !== 21) throw new Error('120');
if (reverseDigits(0) !== 0) throw new Error('0');
if (reverseDigits(7) !== 7) throw new Error('7');

solution:
function digitSum(n) {
  let s = 0;
  while (n > 0) {
    s += n % 10;
    n = Math.trunc(n / 10);
  }
  return s;
}

tests:
if (digitSum(1234) !== 10) throw new Error('1234');
if (digitSum(0) !== 0) throw new Error('0');
if (digitSum(9) !== 9) throw new Error('9');
if (digitSum(105) !== 6) throw new Error('105');

