}

solution:
function polyHash(s, base, mod) {
  let h = 0;
  for (let i = 0; i < s.length; i++) h = (h * base + s.charCodeAt(i)) % mod;
  return h;
}

tests:
for (const s of ['tea', 'eat', 'hi', '', 'a']) {
  const h = polyHash(s, 31, 8);
  if (!Number.isInteger(h) || h < 0 || h >= 8) throw new Error('range: ' + s);
}
if (polyHash('', 31, 8) !== 0) throw new Error('empty');
if (polyHash('tea', 31, 8) !== polyHash('tea', 31, 8)) throw new Error('deterministic');

